import { Injectable } from '@angular/core';
import { BehaviorSubject } from 'rxjs';
import { FirebaseService } from './firebase.service';

const DEFAULT_CATEGORIES = ['Cibo', 'Trasporti', 'Intrattenimento', 'Alloggio', 'Shopping', 'Altro'];

@Injectable({ providedIn: 'root' })
export class CategoryService {
  private categoriesSubject = new BehaviorSubject<string[]>([]);
  categories$ = this.categoriesSubject.asObservable();

  private keyMap = new Map<string, string>(); // value → firebase key
  private seeded = false;

  constructor(private fb: FirebaseService) {}

  listenCategories(): void {
    const uid = this.fb.uid;
    if (!uid) return;

    this.fb.listen(`users/${uid}/categories`).subscribe((snapshot: any) => {
      const items: string[] = [];
      this.keyMap.clear();
      snapshot.forEach((child: any) => {
        const val = child.val() as string;
        items.push(val);
        this.keyMap.set(val, child.key);
      });
      items.sort((a, b) => a.localeCompare(b));
      this.categoriesSubject.next(items);

      if (items.length === 0 && !this.seeded) {
        this.seeded = true;
        DEFAULT_CATEGORIES.forEach((cat) => {
          this.fb.push(`users/${uid}/categories`, cat);
        });
      }
    });
  }

  async addCategory(name: string): Promise<void> {
    const trimmed = name.trim();
    if (!trimmed) throw new Error('empty');
    const existing = this.categoriesSubject.value;
    if (existing.some((c) => c.toLowerCase() === trimmed.toLowerCase())) {
      throw new Error('duplicate');
    }
    const uid = this.fb.uid;
    if (!uid) throw new Error('Not authenticated');
    await this.fb.push(`users/${uid}/categories`, trimmed);
  }

  async removeCategory(name: string): Promise<void> {
    const uid = this.fb.uid;
    if (!uid) throw new Error('Not authenticated');
    const key = this.keyMap.get(name);
    if (key) {
      await this.fb.remove(`users/${uid}/categories/${key}`);
    }
  }
}
