import { Component, OnInit } from '@angular/core';
import { MatCardModule } from '@angular/material/card';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatSelectModule } from '@angular/material/select';
import { MatListModule } from '@angular/material/list';
import { MatProgressBarModule } from '@angular/material/progress-bar';
import { Subscription } from 'rxjs';
import { ExpenseService } from '../../services/expense.service';
import { PeopleService } from '../../services/people.service';
import { CategoryService } from '../../services/category.service';
import { Expense } from '../../models/expense.model';

@Component({
  selector: 'app-overview',
  standalone: true,
  imports: [
    MatCardModule,
    MatFormFieldModule,
    MatSelectModule,
    MatListModule,
    MatProgressBarModule,
  ],
  templateUrl: './overview.html',
  styleUrl: './overview.css',
})
export class OverviewComponent implements OnInit {
  selectedMonth: number;
  selectedYear: number;
  selectedPerson = '';
  selectedCategory = '';

  people: string[] = [];
  categories: string[] = [];
  availableYears: number[] = [];

  expenses: Expense[] = [];
  loading = false;

  months = [
    { value: -1, label: 'Tutti' },
    { value: 0, label: 'Gennaio' },
    { value: 1, label: 'Febbraio' },
    { value: 2, label: 'Marzo' },
    { value: 3, label: 'Aprile' },
    { value: 4, label: 'Maggio' },
    { value: 5, label: 'Giugno' },
    { value: 6, label: 'Luglio' },
    { value: 7, label: 'Agosto' },
    { value: 8, label: 'Settembre' },
    { value: 9, label: 'Ottobre' },
    { value: 10, label: 'Novembre' },
    { value: 11, label: 'Dicembre' },
  ];

  private querySub: Subscription | null = null;

  constructor(
    private expenseService: ExpenseService,
    private peopleService: PeopleService,
    private categoryService: CategoryService,
  ) {
    const now = new Date();
    this.selectedMonth = now.getMonth();
    this.selectedYear = now.getFullYear();
  }

  ngOnInit(): void {
    this.peopleService.people$.subscribe((p) => (this.people = p));
    this.categoryService.categories$.subscribe((c) => (this.categories = c));
    this.expenseService.expenses$.subscribe((expenses) => {
      const years = new Set(expenses.map((e) => parseInt(e.date.substring(0, 4), 10)));
      this.availableYears = Array.from(years).sort((a, b) => b - a);
    });
    this.loadData();
  }

  onPeriodChange(): void {
    this.loadData();
  }

  onLocalFilterChange(): void {
    // triggers re-computation via getters
  }

  private loadData(): void {
    this.loading = true;
    this.querySub?.unsubscribe();
    this.querySub = this.expenseService.queryExpenses(this.selectedYear, this.selectedMonth).subscribe((expenses) => {
      this.expenses = expenses;
      this.loading = false;
    });
  }

  get filteredExpenses(): Expense[] {
    return this.expenses.filter((e) => {
      if (this.selectedPerson && e.who !== this.selectedPerson) return false;
      if (this.selectedCategory && e.category !== this.selectedCategory) return false;
      return true;
    });
  }

  get totalAmount(): string {
    return this.filteredExpenses.reduce((sum, e) => sum + e.amount, 0).toFixed(2);
  }

  get expenseCount(): number {
    return this.filteredExpenses.length;
  }

  get averageAmount(): string {
    const total = this.filteredExpenses.reduce((sum, e) => sum + e.amount, 0);
    return this.filteredExpenses.length > 0 ? (total / this.filteredExpenses.length).toFixed(2) : '0.00';
  }

  get perPersonTotals(): { name: string; total: string }[] {
    const map = new Map<string, number>();
    this.filteredExpenses.forEach((e) => {
      map.set(e.who, (map.get(e.who) ?? 0) + e.amount);
    });
    return Array.from(map.entries())
      .map(([name, total]) => ({ name, total: total.toFixed(2) }))
      .sort((a, b) => parseFloat(b.total) - parseFloat(a.total));
  }

  get perCategoryTotals(): { name: string; total: string }[] {
    const map = new Map<string, number>();
    this.filteredExpenses.forEach((e) => {
      map.set(e.category, (map.get(e.category) ?? 0) + e.amount);
    });
    return Array.from(map.entries())
      .filter(([, total]) => total > 0)
      .map(([name, total]) => ({ name, total: total.toFixed(2) }))
      .sort((a, b) => parseFloat(b.total) - parseFloat(a.total));
  }
}
