import { Component, OnInit, ViewChild, AfterViewInit } from '@angular/core';

import { MatCardModule } from '@angular/material/card';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatSelectModule } from '@angular/material/select';
import { MatTableModule, MatTableDataSource } from '@angular/material/table';
import { MatSortModule, MatSort } from '@angular/material/sort';
import { MatPaginatorModule, MatPaginator } from '@angular/material/paginator';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatProgressBarModule } from '@angular/material/progress-bar';
import { Subscription } from 'rxjs';
import { ExpenseService } from '../../services/expense.service';
import { NotificationService } from '../../services/notification.service';
import { Expense } from '../../models/expense.model';

@Component({
  selector: 'app-expense-list',
  standalone: true,
  imports: [
    MatCardModule,
    MatFormFieldModule,
    MatSelectModule,
    MatTableModule,
    MatSortModule,
    MatPaginatorModule,
    MatButtonModule,
    MatIconModule,
    MatProgressBarModule,
  ],
  templateUrl: './expense-list.html',
  styleUrl: './expense-list.css',
})
export class ExpenseListComponent implements OnInit, AfterViewInit {
  displayedColumns = ['who', 'amount', 'date', 'where', 'category', 'notes', 'actions'];
  dataSource = new MatTableDataSource<Expense>([]);
  loading = false;
  deleteConfirmId: string | null = null;

  selectedMonth: number;
  selectedYear: number;
  availableYears: number[] = [];

  months = [
    { value: -1, label: 'Tutti' },
    { value: 0, label: 'Gennaio' },
    { value: 1, label: 'Febbraio' },
    { value: 2, label: 'Marzo' },
    { value: 3, label: 'Aprile' },
    { value: 4, label: 'Maggio' },
    { value: 5, label: 'Giugno' },
    { value: 6, label: 'Luglio' },
    { value: 7, label: 'Agosto' },
    { value: 8, label: 'Settembre' },
    { value: 9, label: 'Ottobre' },
    { value: 10, label: 'Novembre' },
    { value: 11, label: 'Dicembre' },
  ];

  @ViewChild(MatSort) sort!: MatSort;
  @ViewChild(MatPaginator) paginator!: MatPaginator;

  private querySub: Subscription | null = null;

  constructor(
    private expenseService: ExpenseService,
    private notify: NotificationService,
  ) {
    const now = new Date();
    this.selectedMonth = now.getMonth();
    this.selectedYear = now.getFullYear();
  }

  ngOnInit(): void {
    this.expenseService.expenses$.subscribe((expenses) => {
      const years = new Set(expenses.map((e) => parseInt(e.date.substring(0, 4), 10)));
      this.availableYears = Array.from(years).sort((a, b) => b - a);
      if (!this.availableYears.includes(this.selectedYear) && this.availableYears.length > 0) {
        this.availableYears.push(this.selectedYear);
        this.availableYears.sort((a, b) => b - a);
      }
    });
    this.loadData();
  }

  ngAfterViewInit(): void {
    this.dataSource.sort = this.sort;
    this.dataSource.paginator = this.paginator;
  }

  onFilterChange(): void {
    this.loadData();
  }

  private loadData(): void {
    this.loading = true;
    this.querySub?.unsubscribe();
    this.querySub = this.expenseService.queryExpenses(this.selectedYear, this.selectedMonth).subscribe((expenses) => {
      this.dataSource.data = expenses;
      this.loading = false;
      if (this.paginator) {
        this.paginator.firstPage();
      }
    });
  }

  formatDate(dateStr: string): string {
    const [y, m, d] = dateStr.split('-');
    return `${d}/${m}/${y}`;
  }

  formatAmount(amount: number): string {
    return `€${amount.toFixed(2)}`;
  }

  confirmDelete(id: string): void {
    this.deleteConfirmId = id;
  }

  cancelDelete(): void {
    this.deleteConfirmId = null;
  }

  async doDelete(id: string): Promise<void> {
    try {
      await this.expenseService.deleteExpense(id);
      this.notify.show('Spesa eliminata');
      this.deleteConfirmId = null;
    } catch {
      this.notify.show('Errore nella cancellazione', 'error');
    }
  }
}
