import { Component, inject } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { AsyncPipe } from '@angular/common';
import { MatCardModule } from '@angular/material/card';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { MatButtonModule } from '@angular/material/button';
import { MatChipsModule } from '@angular/material/chips';
import { MatIconModule } from '@angular/material/icon';
import { MatProgressBarModule } from '@angular/material/progress-bar';
import { CategoryService } from '../../services/category.service';
import { NotificationService } from '../../services/notification.service';

@Component({
  selector: 'app-categories',
  standalone: true,
  imports: [
    FormsModule,
    AsyncPipe,
    MatCardModule,
    MatFormFieldModule,
    MatInputModule,
    MatButtonModule,
    MatChipsModule,
    MatIconModule,
    MatProgressBarModule,
  ],
  templateUrl: './categories.html',
  styleUrl: './categories.css',
})
export class CategoriesComponent {
  private categoryService = inject(CategoryService);
  private notify = inject(NotificationService);

  categories$ = this.categoryService.categories$;
  newName = '';
  adding = false;

  async add(): Promise<void> {
    this.adding = true;
    try {
      await this.categoryService.addCategory(this.newName);
      this.notify.show('Categoria aggiunta!');
      this.newName = '';
    } catch (err: unknown) {
      const msg = (err as Error).message;
      if (msg === 'empty') {
        this.notify.show('La categoria non può essere vuota', 'error');
      } else if (msg === 'duplicate') {
        this.notify.show('Categoria già esistente', 'error');
      }
    } finally {
      this.adding = false;
    }
  }

  async remove(name: string): Promise<void> {
    await this.categoryService.removeCategory(name);
    this.notify.show('Categoria rimossa');
  }
}
