import { Injectable } from '@angular/core';
import { BehaviorSubject, Observable, Subscription } from 'rxjs';
import { FirebaseService } from './firebase.service';
import { Expense } from '../models/expense.model';

function parseExpenses(snapshot: any): Expense[] {
  const items: Expense[] = [];
  snapshot.forEach((child: any) => {
    items.push({ id: child.key, ...child.val() });
  });
  items.sort((a, b) => {
    const dateCompare = b.date.localeCompare(a.date);
    return dateCompare !== 0 ? dateCompare : b.createdAt - a.createdAt;
  });
  return items;
}

@Injectable({ providedIn: 'root' })
export class ExpenseService {
  private expensesSubject = new BehaviorSubject<Expense[]>([]);
  expenses$ = this.expensesSubject.asObservable();

  private loadingSubject = new BehaviorSubject<boolean>(false);
  loading$ = this.loadingSubject.asObservable();

  private subscription: Subscription | null = null;

  constructor(private fb: FirebaseService) {}

  listenExpenses(): void {
    const uid = this.fb.uid;
    if (!uid) return;

    this.loadingSubject.next(true);
    this.subscription?.unsubscribe();

    this.subscription = this.fb.listenOrdered(`users/${uid}/expenses`, 'date').subscribe((snapshot: any) => {
      this.expensesSubject.next(parseExpenses(snapshot));
      this.loadingSubject.next(false);
    });
  }

  queryExpenses(year: number, month: number): Observable<Expense[]> {
    const uid = this.fb.uid;
    if (!uid) return new Observable((sub) => { sub.next([]); sub.complete(); });

    if (year === -1) {
      return new Observable((subscriber) => {
        const sub = this.fb.listen(`users/${uid}/expenses`).subscribe((snapshot: any) => {
          subscriber.next(parseExpenses(snapshot));
        });
        return () => sub.unsubscribe();
      });
    }

    let start: string;
    let end: string;

    if (month === -1) {
      start = `${year}-01-01`;
      end = `${year}-12-31`;
    } else {
      const m = (month + 1).toString().padStart(2, '0');
      const lastDay = new Date(year, month + 1, 0).getDate();
      start = `${year}-${m}-01`;
      end = `${year}-${m}-${lastDay.toString().padStart(2, '0')}`;
    }

    return new Observable((subscriber) => {
      const sub = this.fb.listenRange(`users/${uid}/expenses`, 'date', start, end).subscribe((snapshot: any) => {
        subscriber.next(parseExpenses(snapshot));
      });
      return () => sub.unsubscribe();
    });
  }

  addExpense(data: Omit<Expense, 'id' | 'uid' | 'createdAt'>): Promise<string | null> {
    const uid = this.fb.uid;
    if (!uid) return Promise.reject('Not authenticated');

    return this.fb.push(`users/${uid}/expenses`, {
      ...data,
      uid,
      createdAt: Date.now(),
    });
  }

  deleteExpense(id: string): Promise<void> {
    const uid = this.fb.uid;
    if (!uid) return Promise.reject('Not authenticated');
    return this.fb.remove(`users/${uid}/expenses/${id}`);
  }
}
