import { Injectable } from '@angular/core';
import { BehaviorSubject } from 'rxjs';
import { FirebaseService } from './firebase.service';

@Injectable({ providedIn: 'root' })
export class PeopleService {
  private peopleSubject = new BehaviorSubject<string[]>([]);
  people$ = this.peopleSubject.asObservable();

  private keyMap = new Map<string, string>(); // value → firebase key

  constructor(private fb: FirebaseService) {}

  listenPeople(): void {
    const uid = this.fb.uid;
    if (!uid) return;

    this.fb.listen(`users/${uid}/people`).subscribe((snapshot: any) => {
      const items: string[] = [];
      this.keyMap.clear();
      snapshot.forEach((child: any) => {
        const val = child.val() as string;
        items.push(val);
        this.keyMap.set(val, child.key);
      });
      items.sort((a, b) => a.localeCompare(b));
      this.peopleSubject.next(items);
    });
  }

  async addPerson(name: string): Promise<void> {
    const trimmed = name.trim();
    if (!trimmed) throw new Error('empty');
    const existing = this.peopleSubject.value;
    if (existing.some((p) => p.toLowerCase() === trimmed.toLowerCase())) {
      throw new Error('duplicate');
    }
    const uid = this.fb.uid;
    if (!uid) throw new Error('Not authenticated');
    await this.fb.push(`users/${uid}/people`, trimmed);
  }

  async removePerson(name: string): Promise<void> {
    const uid = this.fb.uid;
    if (!uid) throw new Error('Not authenticated');
    const key = this.keyMap.get(name);
    if (key) {
      await this.fb.remove(`users/${uid}/people/${key}`);
    }
  }
}
