import { Component, inject } from '@angular/core';
import { AsyncPipe } from '@angular/common';
import { ReactiveFormsModule, FormGroup, FormControl, Validators } from '@angular/forms';
import { MatCardModule } from '@angular/material/card';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { MatSelectModule } from '@angular/material/select';
import { MatButtonModule } from '@angular/material/button';
import { MatProgressBarModule } from '@angular/material/progress-bar';
import { MatDatepickerModule } from '@angular/material/datepicker';
import { MatNativeDateModule } from '@angular/material/core';
import { ExpenseService } from '../../services/expense.service';
import { PeopleService } from '../../services/people.service';
import { CategoryService } from '../../services/category.service';
import { NotificationService } from '../../services/notification.service';

@Component({
  selector: 'app-expense-form',
  standalone: true,
  imports: [
    AsyncPipe,
    ReactiveFormsModule,
    MatCardModule,
    MatFormFieldModule,
    MatInputModule,
    MatSelectModule,
    MatButtonModule,
    MatProgressBarModule,
    MatDatepickerModule,
    MatNativeDateModule,
  ],
  templateUrl: './expense-form.html',
  styleUrl: './expense-form.css',
})
export class ExpenseFormComponent {
  private expenseService = inject(ExpenseService);
  private peopleService = inject(PeopleService);
  private categoryService = inject(CategoryService);
  private notify = inject(NotificationService);

  people$ = this.peopleService.people$;
  categories$ = this.categoryService.categories$;
  saving = false;

  form = new FormGroup({
    who: new FormControl('', Validators.required),
    amount: new FormControl<number | null>(null, [Validators.required, Validators.min(0.01)]),
    date: new FormControl<Date>(this.today(), Validators.required),
    where: new FormControl('', Validators.required),
    category: new FormControl('', Validators.required),
    notes: new FormControl(''),
  });

  async submit(): Promise<void> {
    if (this.form.invalid) {
      this.notify.show('Compila tutti i campi obbligatori', 'error');
      return;
    }

    this.saving = true;
    try {
      const v = this.form.value;
      await this.expenseService.addExpense({
        who: v.who!,
        amount: parseFloat(Number(v.amount).toFixed(2)),
        date: this.formatDate(v.date!),
        where: v.where!.trim(),
        category: v.category!,
        notes: (v.notes ?? '').trim(),
      });
      this.notify.show('Spesa aggiunta!');
      this.resetForm();
    } catch {
      this.notify.show('Errore nel salvataggio', 'error');
    } finally {
      this.saving = false;
    }
  }

  resetForm(): void {
    this.form.reset({ date: this.today() });
  }

  private today(): Date {
    return new Date();
  }

  private formatDate(d: Date): string {
    return `${d.getFullYear()}-${(d.getMonth() + 1).toString().padStart(2, '0')}-${d.getDate().toString().padStart(2, '0')}`;
  }
}
